package com.secman.service

import com.secman.domain.RequirementIdSequence
import com.secman.repository.RequirementIdSequenceRepository
import com.secman.repository.RequirementRepository
import io.micronaut.context.event.StartupEvent
import io.micronaut.runtime.event.annotation.EventListener
import io.micronaut.scheduling.annotation.Async
import io.micronaut.transaction.annotation.Transactional
import jakarta.inject.Inject
import jakarta.inject.Singleton
import org.slf4j.LoggerFactory
import java.time.Instant

/**
 * Migration service that assigns unique internalId to existing requirements with blank IDs.
 *
 * This service runs on application startup and ensures all requirements have proper
 * ID.Revision format (e.g., REQ-001.1) for Excel exports.
 *
 * Related to: Fix for requirements Excel export showing only revision numbers.
 */
@Singleton
open class RequirementIdMigrationService(
    @Inject private val requirementRepository: RequirementRepository,
    @Inject private val requirementIdService: RequirementIdService,
    @Inject private val sequenceRepository: RequirementIdSequenceRepository
) {
    private val log = LoggerFactory.getLogger(RequirementIdMigrationService::class.java)

    @EventListener
    @Async
    @Transactional
    open fun onStartup(event: StartupEvent) {
        try {
            initializeSequenceIfEmpty()
            migrateBlankInternalIds()
        } catch (e: Exception) {
            log.error("Failed to migrate requirement IDs on startup: {}", e.message, e)
        }
    }

    /**
     * Initialize the sequence table if it's empty.
     * Calculates the next value based on existing requirements with internalId.
     */
    @Transactional
    open fun initializeSequenceIfEmpty() {
        if (sequenceRepository.existsById(1L)) {
            log.debug("Requirement ID sequence already initialized")
            return
        }

        // Calculate the next value based on existing requirements
        val existingIds = requirementRepository.findAll()
            .filter { it.internalId.isNotBlank() }
            .mapNotNull { extractIdNumber(it.internalId) }

        val nextValue = if (existingIds.isEmpty()) 1 else existingIds.max() + 1

        val sequence = RequirementIdSequence(
            id = 1L,
            nextValue = nextValue,
            updatedAt = Instant.now()
        )
        sequenceRepository.save(sequence)
        log.info("Initialized requirement ID sequence with next_value={}", nextValue)
    }

    /**
     * Extract the numeric part from an internal ID like "REQ-001" -> 1
     */
    private fun extractIdNumber(internalId: String): Int? {
        return try {
            // Handle formats like "REQ-001" or "REQ-1234"
            val numPart = internalId.removePrefix("REQ-")
            numPart.toIntOrNull()
        } catch (e: Exception) {
            null
        }
    }

    @Transactional
    open fun migrateBlankInternalIds(): Int {
        val requirements = requirementRepository.findAll()
            .filter { it.internalId.isBlank() }

        if (requirements.isEmpty()) {
            log.info("No requirements with blank internalId found")
            return 0
        }

        log.info("Migrating {} requirements with blank internalId", requirements.size)

        requirements.forEach { requirement ->
            requirement.internalId = requirementIdService.getNextId()
            requirementRepository.update(requirement)
            log.debug("Assigned internalId {} to requirement '{}'", requirement.internalId, requirement.shortreq)
        }

        log.info("Successfully migrated {} requirements with unique IDs", requirements.size)
        return requirements.size
    }
}

package com.secman.service

import com.secman.domain.IdentityProvider
import com.secman.repository.IdentityProviderRepository
import io.micronaut.context.event.ApplicationEventListener
import io.micronaut.runtime.event.ApplicationStartupEvent
import jakarta.inject.Singleton
import org.slf4j.LoggerFactory

@Singleton
class ProviderInitializationService(
    private val identityProviderRepository: IdentityProviderRepository
) : ApplicationEventListener<ApplicationStartupEvent> {

    private val logger = LoggerFactory.getLogger(ProviderInitializationService::class.java)

    override fun onApplicationEvent(event: ApplicationStartupEvent) {
        initializeDefaultProviders()
    }

    private fun initializeDefaultProviders() {
        try {
            // Check if GitHub provider exists
            val existingGitHubProvider = identityProviderRepository.findByNameIgnoreCase("GitHub")

            if (existingGitHubProvider.isEmpty) {
                logger.info("Creating default GitHub OAuth provider")

                val githubProvider = IdentityProvider(
                    name = "GitHub",
                    type = IdentityProvider.ProviderType.OIDC,
                    clientId = System.getenv("GITHUB_CLIENT_ID") ?: "your-github-client-id",
                    clientSecret = System.getenv("GITHUB_CLIENT_SECRET") ?: "your-github-client-secret",
                    authorizationUrl = "https://github.com/login/oauth/authorize",
                    tokenUrl = "https://github.com/login/oauth/access_token",
                    userInfoUrl = "https://api.github.com/user",
                    scopes = "user:email",
                    enabled = true,
                    autoProvision = true,
                    buttonText = "Sign in with GitHub",
                    buttonColor = "#333333"
                )

                val saved = identityProviderRepository.save(githubProvider)
                logger.info("Created GitHub OAuth provider with ID: {}", saved.id)

                if (System.getenv("GITHUB_CLIENT_ID") == null || System.getenv("GITHUB_CLIENT_SECRET") == null) {
                    logger.warn("GitHub OAuth provider created with placeholder credentials. " +
                               "Please set GITHUB_CLIENT_ID and GITHUB_CLIENT_SECRET environment variables " +
                               "or update the provider configuration via the API.")
                }
            } else {
                logger.info("GitHub OAuth provider already exists with ID: {}", existingGitHubProvider.get().id)
            }

            // Check if Microsoft provider exists
            val existingMicrosoftProvider = identityProviderRepository.findByNameIgnoreCase("Microsoft")

            if (existingMicrosoftProvider.isEmpty) {
                val microsoftClientId = System.getenv("MICROSOFT_CLIENT_ID")
                val microsoftClientSecret = System.getenv("MICROSOFT_CLIENT_SECRET")
                val microsoftTenantId = System.getenv("MICROSOFT_TENANT_ID")

                if (microsoftClientId != null && microsoftClientSecret != null && microsoftTenantId != null) {
                    logger.info("Creating default Microsoft OAuth provider")

                    val microsoftProvider = IdentityProvider(
                        name = "Microsoft",
                        type = IdentityProvider.ProviderType.OIDC,
                        clientId = microsoftClientId,
                        clientSecret = microsoftClientSecret,
                        tenantId = microsoftTenantId,
                        discoveryUrl = "https://login.microsoftonline.com/$microsoftTenantId/v2.0/.well-known/openid-configuration",
                        authorizationUrl = "https://login.microsoftonline.com/$microsoftTenantId/oauth2/v2.0/authorize",
                        tokenUrl = "https://login.microsoftonline.com/$microsoftTenantId/oauth2/v2.0/token",
                        userInfoUrl = "https://graph.microsoft.com/v1.0/me",
                        issuer = "https://login.microsoftonline.com/$microsoftTenantId/v2.0",
                        jwksUri = "https://login.microsoftonline.com/$microsoftTenantId/discovery/v2.0/keys",
                        scopes = "openid email profile",
                        enabled = false,  // Disabled by default, admin must enable
                        autoProvision = true,
                        buttonText = "Sign in with Microsoft",
                        buttonColor = "#0078d4"
                    )

                    val saved = identityProviderRepository.save(microsoftProvider)
                    logger.info("Created Microsoft OAuth provider with ID: {} (disabled by default)", saved.id)
                } else {
                    logger.info("Skipping Microsoft OAuth provider creation - environment variables not set. " +
                               "To auto-create, set MICROSOFT_CLIENT_ID, MICROSOFT_CLIENT_SECRET, and MICROSOFT_TENANT_ID.")
                }
            } else {
                logger.info("Microsoft OAuth provider already exists with ID: {}", existingMicrosoftProvider.get().id)
            }

        } catch (e: Exception) {
            logger.error("Failed to initialize default providers: {}", e.message, e)
        }
    }
}

package com.secman.config

import io.micronaut.flyway.FlywayConfigurationCustomizer
import jakarta.inject.Named
import jakarta.inject.Singleton
import org.flywaydb.core.api.configuration.FluentConfiguration
import org.slf4j.LoggerFactory

/**
 * Repairs Flyway schema history before migration runs.
 * - Removes failed migration entries (success=0)
 * - Drops and recreates flyway_schema_history if baseline is wrong
 *
 * This handles the case where Flyway is introduced to an existing database
 * where Hibernate hbm2ddl.auto:update had previously managed the schema.
 */
@Singleton
@Named("default")
class FlywayRepairCustomizer : FlywayConfigurationCustomizer {
    private val logger = LoggerFactory.getLogger(FlywayRepairCustomizer::class.java)

    override fun getName(): String = "default"

    override fun customizeFluentConfiguration(fluentConfiguration: FluentConfiguration) {
        try {
            val ds = fluentConfiguration.dataSource ?: return
            ds.connection.use { conn ->
                val stmt = conn.createStatement()

                // Check if flyway_schema_history exists
                val rs = stmt.executeQuery(
                    "SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = DATABASE() AND table_name = 'flyway_schema_history'"
                )
                rs.next()
                val tableExists = rs.getInt(1) > 0
                rs.close()

                if (tableExists) {
                    // Check if baseline is wrong (version < 185 means old/broken state)
                    val baselineRs = stmt.executeQuery(
                        "SELECT version FROM flyway_schema_history WHERE type = 'BASELINE' ORDER BY installed_rank LIMIT 1"
                    )
                    val needsReset = if (baselineRs.next()) {
                        val baselineVersion = baselineRs.getString(1)
                        baselineVersion.toIntOrNull()?.let { it < 185 } ?: true
                    } else {
                        // No baseline at all, check for failed entries
                        false
                    }
                    baselineRs.close()

                    if (needsReset) {
                        logger.warn("Dropping flyway_schema_history to re-baseline (old baseline found)")
                        stmt.executeUpdate("DROP TABLE flyway_schema_history")
                        // Flyway will re-create and baseline at the configured version
                    } else {
                        // Just clean up any failed entries
                        val deleted = stmt.executeUpdate(
                            "DELETE FROM flyway_schema_history WHERE success = 0"
                        )
                        if (deleted > 0) {
                            logger.warn("Removed $deleted failed migration entries from flyway_schema_history")
                        }
                    }
                }

                stmt.close()
            }
        } catch (e: Exception) {
            logger.warn("Could not repair flyway_schema_history: ${e.message}")
        }
    }
}

package com.secman.config

import com.secman.domain.User
import com.secman.repository.UserRepository
import io.micronaut.context.event.ApplicationEventListener
import io.micronaut.runtime.event.ApplicationStartupEvent
import io.micronaut.transaction.annotation.Transactional
import jakarta.inject.Singleton
import org.slf4j.LoggerFactory
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder

/**
 * Creates a default admin user on first application startup if no users exist.
 *
 * Default credentials:
 *   Username: admin
 *   Email:    admin@localhost
 *   Password: password
 *   Roles:    ADMIN, USER
 *
 * IMPORTANT: Change the default password immediately after first login in production.
 */
@Singleton
open class DefaultAdminBootstrapper(
    private val userRepository: UserRepository
) : ApplicationEventListener<ApplicationStartupEvent> {

    private val log = LoggerFactory.getLogger(DefaultAdminBootstrapper::class.java)
    private val passwordEncoder = BCryptPasswordEncoder()

    companion object {
        const val DEFAULT_ADMIN_USERNAME = "admin"
        const val DEFAULT_ADMIN_EMAIL = "admin@localhost"
        const val DEFAULT_ADMIN_PASSWORD = "password"
    }

    override fun onApplicationEvent(event: ApplicationStartupEvent) {
        bootstrapDefaultAdmin()
    }

    @Transactional
    open fun bootstrapDefaultAdmin() {
        try {
            val userCount = userRepository.count()
            if (userCount > 0) {
                log.debug("Users already exist (count={}), skipping default admin creation", userCount)
                return
            }

            val admin = User(
                username = DEFAULT_ADMIN_USERNAME,
                email = DEFAULT_ADMIN_EMAIL,
                passwordHash = passwordEncoder.encode(DEFAULT_ADMIN_PASSWORD)!!,
                roles = mutableSetOf(User.Role.ADMIN, User.Role.USER),
                authSource = User.AuthSource.LOCAL
            )

            userRepository.save(admin)
            log.warn("==========================================================")
            log.warn("  DEFAULT ADMIN USER CREATED")
            log.warn("  Username: {}", DEFAULT_ADMIN_USERNAME)
            log.warn("  Password: {} (CHANGE IMMEDIATELY!)", DEFAULT_ADMIN_PASSWORD)
            log.warn("==========================================================")
        } catch (e: Exception) {
            log.error("Failed to bootstrap default admin user: {}", e.message, e)
        }
    }
}

