232→            args[0] == "delete-all-requirements" -> {
233→                // Use Picocli with Micronaut DI for delete-all-requirements command
234→                // Feature: 057-cli-mcp-requirements
235→                val subArgs = args.drop(1).toTypedArray()
236→                ApplicationContext.run().use { ctx ->
237→                    PicocliRunner.run(DeleteAllRequirementsCommand::class.java, ctx, *subArgs)
238→                }
