253→                ApplicationContext.run().use { ctx ->
254→                    PicocliRunner.run(DeduplicateVulnerabilitiesCommand::class.java, ctx, *subArgs)
255→                }
256→                0
257→            }
258→            else -> {
259→                System.err.println("ERROR: Unknown command: '${args[0]}'")
260→
261→                // Suggest parent command for known subcommands used at the wrong level
262→                val subcommandHints = mapOf(
263→                    "list-bucket" to "manage-user-mappings",
264→                    "import-s3" to "manage-user-mappings",
265→                    "add-domain" to "manage-user-mappings",
266→                    "add-aws" to "manage-user-mappings",
267→                    "assign-assets" to "manage-workgroups",
