                }
                0
            }
            args[0] == "add-vulnerability" -> {
                // Use Picocli with Micronaut DI for add-vulnerability command
                // Feature: 052-cli-add-vulnerability
                val subArgs = args.drop(1).toTypedArray()
                ApplicationContext.run().use { ctx ->
