                        }
                        args[i] == "--client-secret" && i + 1 < args.size -> {
                            serversCommand.clientSecret = args[i + 1]
                            i++
                        }
                        args[i] == "--save" -> serversCommand.save = true
                        args[i] == "--dry-run" -> serversCommand.dryRun = true
                        args[i] == "--verbose" -> serversCommand.verbose = true
